    64	fn getProcessNameDarwin(alloc: std.mem.Allocator, pid: std.posix.pid_t) !?[]const u8 {
    65	    // Use proc_name() from libproc (available via libc on macOS).
    66	    const proc_name_fn = struct {
    67	        extern "c" fn proc_name(pid: i32, buffer: [*]u8, buffersize: u32) i32;
    68	    };
    69	    var name_buf: [256]u8 = undefined;
    70	    const len = proc_name_fn.proc_name(@intCast(pid), &name_buf, name_buf.len);
    71	    if (len <= 0) return null;
    72	    return try alloc.dupe(u8, name_buf[0..@intCast(len)]);
