    75	fn getProcessNameLinux(alloc: std.mem.Allocator, pid: std.posix.pid_t) !?[]const u8 {
    76	    var path_buf: [256]u8 = undefined;
    77	    const path = std.fmt.bufPrint(&path_buf, "/proc/{d}/comm", .{pid}) catch return null;
    78	    // Use libc to read the file
    79	    var name_buf: [256]u8 = undefined;
    80	    var cpath_buf: [256]u8 = undefined;
    81	    if (path.len >= cpath_buf.len) return null;
    82	    @memcpy(cpath_buf[0..path.len], path);
    83	    cpath_buf[path.len] = 0;
    84	    const cpath: [*:0]const u8 = @ptrCast(cpath_buf[0..path.len :0]);
    85	    const fd = std.c.open(cpath, .{ .ACCMODE = .RDONLY }, 0);
    86	    if (fd < 0) return null;
    87	    defer _ = std.c.close(fd);
    88	    const n = std.c.read(fd, &name_buf, name_buf.len);
